import json,re
from pathlib import Path
patterns=[r'broken the siege',r'siege has been broken',r'break the siege',r'break.*siege',r'besieged']
pat=re.compile('|'.join(patterns),re.I)
for p in sorted(Path('articles/2026/01').glob('*/articles.jsonl')):
    hits=[]
    for i,line in enumerate(p.open(),1):
        try:a=json.loads(line)
        except:continue
        text=(a.get('title') or '')+'\\n'+(a.get('content') or '')
        if 'Sudan' in text and pat.search(text):
            hits.append((i,a.get('date_publish'),a.get('source'),a.get('title')))
    if hits:
        print('\\n',p)
        for h in hits[:10]: print(h)
PY"

